module top_module(X_A, B, ADDSUB, RES);parameter  WIDTH = 8;
    input                   ADDSUB;
    input       [WIDTH-1:0] X_A;
    input       [WIDTH-1:0] B;
    output reg  [WIDTH-1:0] RES;

    always @(X_A or B or ADDSUB)
    begin
        if (ADDSUB == 1'b0)
	    RES = X_A + B;
        else
	    RES = X_A - B;
    end

endmodule
